const root = $json.body ?? $json;
const stage =
  root.pipeline_stage_name ??
  root.pipelineStageName ??
  root.stage_name ??
  root.stageName ??
  root.newStageName ??
  root.opportunity?.pipelineStageName ??
  root.opportunity?.stageName ??
  '';
const stageStr = String(stage).toLowerCase();
const isReferral = stageStr.includes('referral partner');
return [{
  json: {
    isReferralPartnerStage: isReferral,
    receivedAt: new Date().toISOString(),
    event: root.event_type || root.type || 'opportunity_stage',
    ghlContactId: root.contact_id || root.contactId || root.contact?.id || root.opportunity?.contactId,
    ghlOpportunityId: root.opportunity_id || root.opportunityId || root.opportunity?.id,
    contactName: root.contact_name || root.contactName || root.contact?.name,
    pipelineStageName: String(stage || ''),
    opportunitySource: root.source || root.opportunity?.source,
    notes: '',
    raw: root
  }
}];
